import subprocess
import os

def backup_directory(path, format):
    validated_path = os.path.abspath(path)
    if not os.path.isdir(validated_path):
        raise ValueError("Invalid directory path")

    if format == 'tar.gz':
        subprocess.run(['tar', '-czf', f'{validated_path}.tar.gz', validated_path])
    elif format == 'tar.bz2':
        subprocess.run(['tar', '-cjf', f'{validated_path}.tar.bz2', validated_path])
    elif format == 'zip':
        subprocess.run(['zip', '-r', f'{validated_path}.zip', validated_path])
    elif format == '7z':
        subprocess.run(['7z', 'a', f'{validated_path}.7z', validated_path])
    else:
        raise ValueError("Unsupported compression format")

# Example usage
